// 存储键名常量
export const STORAGE_KEYS = {
  ACCESS_TOKEN: 'access_token',
  REFRESH_TOKEN: 'refresh_token',
  TOKEN_EXPIRATION: 'token_expiration',
  REMEMBER_ME: 'remember_me',
  REMEMBERED_PHONE: 'remembered_phone'
}

// 过期时间常量
export const EXPIRATION = {
  NORMAL: 2 * 60 * 60 * 1000,    // 普通登录 2 小时
  REMEMBER: 7 * 24 * 60 * 60 * 1000  // 记住我 7 天
}

// 存储操作辅助函数
export const storage = {
  // 获取认证信息
  getAuth() {
    const access = localStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN)
    const refresh = localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN)
    const expiration = localStorage.getItem(STORAGE_KEYS.TOKEN_EXPIRATION)

    return access ? {
      access,
      refresh,
      expiration: parseInt(expiration)
    } : null
  },

  // 保存认证信息
  saveAuth(tokens, remember = false) {
    const expiration = new Date().getTime() + 
      (remember ? EXPIRATION.REMEMBER : EXPIRATION.NORMAL)

    localStorage.setItem(STORAGE_KEYS.ACCESS_TOKEN, tokens.access)
    localStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN, tokens.refresh)
    localStorage.setItem(STORAGE_KEYS.TOKEN_EXPIRATION, expiration.toString())
  },

  // 清除所有认证相关数据
  clearAuth() {
    Object.values(STORAGE_KEYS).forEach(key => {
      localStorage.removeItem(key)
    })
  }
}
